+  const ignored = new Set<number>();
+  const lines = text.split('\
');
+  let inYaml = lines[0]?.trim() === '---';
+  let fence: string | null = null;
+  let math = false;
+  for (let index = 0; index < lines.length; index++) {
+    const trimmed = lines[index].trim();
+    if (inYaml) {
+      ignored.add(index);
+      if (index > 0 && (trimmed === '---' || trimmed === '...')) inYaml = false;
+      continue;
+    }
+    if (fence) {
+      ignored.add(index);
+      if (new RegExp(`^ {0,3}${fence[0]}{${fence.length},}\\\\s*$`).test(lines[index])) fence = null;
+      continue;
+    }
+    if (math) {
+      ignored.add(index);
+      if (/^\\s*\\$\\$\\s*$/.test(lines[index])) math = false;
+      continue;
+    }
+    const fenceMatch = /^ {0,3}(`{3,}|~{3,})/.exec(lines[index]);
+    if (fenceMatch) {
+      ignored.add(index);
+      fence = fenceMatch[1];
+    } else if (/^\\s*\\$\\$\\s*$/.test(lines[index])) {
+      ignored.add(index);
+      math = true;
+    }
+  }
+  return ignored;
+}
+
+function buildToc(headings: {level: number, text: string, anchor: string}[], options: AutoTocOptions): string[] {
+  const baseLevel = Math.min(...headings.map((heading) => heading.level), options.minLevel);
+  return headings.map((heading, index) => {
+    const indentation = ' '.repeat(Math.max(0, heading.level - baseLevel) * options.indentSize);
+    const marker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.` : options.bulletMarker;
+    return `${indentation}${marker} [${heading.text}](#${heading.anchor})`;
+  });
+}
