+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1')
+      .toLowerCase().replace(/\\s+/g, '-').replace(/[^a-z0-9-_]/g, '').replace(/-+/g, '-').replace(/^-+|-+$/g, '');
