+function toHeadingMatcher(value: string): (heading: string) => boolean {
+  if (value.startsWith('/') && value.endsWith('/') && value.length > 2) {
+    try {
+      const regex = new RegExp(value.slice(1, -1), 'i');
+      return (heading) => regex.test(heading);
+    } catch (_) { /* Treat invalid expressions as literal values. */ }
+  }
+  return (heading) => heading.toLowerCase() === value.toLowerCase();
